mapper.sql:
SELECT
ID

INVOICE_ID

INVOICE_NO

ISSUE_DATE

SPECIAL_INVOICE_MARK

TAX_INCLUSIVE_PRICE_MARK

INVOICE_LINES

TAX_EXCLUSIVE_TOTAL_AMOUNT

TAX_TOTAL_AMOUNT

TAX_INCLUSIVE_TOTAL_AMOUNT

DEDUCTION

NOTE

PAYEE

CHECKER

INVOICE_CLERK

RANDOM_NUM

FILE_URL

FILE_URL_XML

SELLER_TAX_ID

SELLER_NAME

SELLER_ADDR_TEL

SELLER_TEL

SELLER_FINANCIAL_ACCOUNT

SELLER_ACCOUNT

BUYER_TAX_ID

BUYER_NAME

BUYER_ADDR_TEL

BUYER_TEL

BUYER_FINANCIAL_ACCOUNT

BUYER_ACCOUNT

COUNT

CREATE_BY

CREATE_BY_NAME

CREATE_TIME

UPDATE_BY

UPDATE_BY_NAME

UPDATE_TIME

FROM
T_SD_INVOICE_REQUEST


        and ID = #{id}


        and INVOICE_ID = #{invoiceId}


        and INVOICE_NO = #{invoiceNo}


        and ISSUE_DATE = #{issueDate}


        and SPECIAL_INVOICE_MARK = #{specialInvoiceMark}


        and TAX_INCLUSIVE_PRICE_MARK = #{taxInclusivePriceMark}


        and INVOICE_LINES = #{invoiceLines}


        and TAX_EXCLUSIVE_TOTAL_AMOUNT = #{taxExclusiveTotalAmount}


        and TAX_TOTAL_AMOUNT = #{taxTotalAmount}


        and TAX_INCLUSIVE_TOTAL_AMOUNT = #{taxInclusiveTotalAmount}


        and DEDUCTION = #{deduction}


        and NOTE = #{note}


        and PAYEE = #{payee}


        and CHECKER = #{checker}


        and INVOICE_CLERK = #{invoiceClerk}


        and RANDOM_NUM = #{randomNum}


        and FILE_URL = #{fileUrl}


        and FILE_URL_XML = #{fileUrlXml}


        and SELLER_TAX_ID = #{sellerTaxId}


        and SELLER_NAME = #{sellerName}


        and SELLER_ADDR_TEL = #{sellerAddrTel}


        and SELLER_TEL = #{sellerTel}


        and SELLER_FINANCIAL_ACCOUNT = #{sellerFinancialAccount}


        and SELLER_ACCOUNT = #{sellerAccount}


        and BUYER_TAX_ID = #{buyerTaxId}


        and BUYER_NAME = #{buyerName}


        and BUYER_ADDR_TEL = #{buyerAddrTel}


        and BUYER_TEL = #{buyerTel}


        and BUYER_FINANCIAL_ACCOUNT = #{buyerFinancialAccount}


        and BUYER_ACCOUNT = #{buyerAccount}


        and COUNT = #{count}

mapper.select:
SELECT tsria.* FROM T_SD_RED_INVOICE_APPLY tsria LEFT JOIN T_FD_INVOICE tfi ON tsria.INVOICE_ID = TFI.id
STATUS != '2' AND tfi.SYS_INVOICE_CODE = #{invoiceCode}
order by tfi.CREATE_TIME desc
